function lbl = fLblLstTrjV01(slct)% Function Label list for trajectory, ver.1% lbl = fLblLstTrjV01(slct)% gives an array of labels for trajectory.%% slct: selector, 1 for title and label for plots, 2 for title for output text% lbl: output labels%% Kei Nakamura% Created on Sunday, May 9th 2010.% Modified on %%% main if slct==1;    lbl{1} = 'y [m]';    lbl{2} = 'z [m]';    lbl{3} = 's [m]';    lbl{4} = 'B [T]';    lbl{5} = 'Field map [T]';    lbl{6} = 'Smoothed and measured field';    lbl{7} = 'r [m]';    lbl{8} = 'Field along s';elseif slct==2;    lbl{1} = 'kinetic energy_MeV';    lbl{2} = 'momentum_MeV/c';    lbl{3} = 'total energy_MeV';    lbl{4} = 'gamma';    lbl{5} = 'beta';    lbl{6} = 'orbit radius_m';    lbl{7} = 'bending angle_dgr';    lbl{8} = 'bending angle at screen_dgr';    lbl{9} = 'incident angle_dgr';    lbl{10} = 'drift1_m';    lbl{11} = 'drift2_m';    lbl{12} = 'total path_m';    lbl{13} = 'screen_m';    lbl{14} = 'Bpeak_T';    lbl{15} = 'B.m_T.m';    lbl{16} = 'effective length_m';    lbl{17} = 'enge coeff. 1';    lbl{18} = 'enge coeff. 2';    lbl{19} = 'enge coeff. 3';    lbl{20} = 'enge coeff. 4';    lbl{21} = 'enge coeff. 5';    lbl{22} = 'enge coeff. 6';    lbl{23} = 'MagRds_m';end
